import React from "react"
import Carousel from "react-bootstrap/Carousel"
import { FormattedMessage, injectIntl } from "gatsby-plugin-intl"
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome"
import SEO from "../components/seo"
import CoverImgFehmarn from "../images/20191020_Oneness_Fehmarn_02.jpg"
import CoverImgTreibsAnd from "../images/202001_oneness_treibsand_02.jpg"
import CoverImgKlangbar from "../images/202002_oneness_klangbar01.jpg"

const carouselImgs = [{
    title: "Fehmarn",
    img: CoverImgFehmarn
}, {
    title: "Lübeck",
    img: CoverImgTreibsAnd
}, {
    title: "Hamburg",
    img: CoverImgKlangbar
}];

const IndexPage = ({intl}) => (
    <>
        <SEO title="Home"/>
        <h3>Oneness - Music for Life</h3>
        <Carousel interval={3000}>
            {carouselImgs.map(carouselImg => (
                <Carousel.Item key={carouselImg.title} className="oneness-container mb-2">
                    <img src={carouselImg.img} className="img-fluid rounded-lg" alt=""/>
                    <Carousel.Caption>
                        <div className="bottom-center">
                            <h3 className="rounded px-2 py-1 d-inline">
                                <FontAwesomeIcon icon="map-marker-alt"/> {carouselImg.title}
                            </h3>
                        </div>
                    </Carousel.Caption>
                </Carousel.Item>
            ))}
        </Carousel>

        <div className="jumbotron py-4 my-0 text-dark">
            <div className="container">
                <h1>
                    <FormattedMessage id="history"/>
                </h1>
                <p className="lead">
                    {intl.formatMessage({id: "history_text"}, {br: <br/>})}
                </p>
            </div>
        </div>
    </>
);

export default injectIntl(IndexPage)